{
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Write|Edit",
        "hooks": [
          {
            "type": "command",
            "command": "bash -c 'if echo \"$CLAUDE_TOOL_INPUT\" | grep -q \"test_\"; then pytest \"$CLAUDE_TOOL_INPUT\" -x --tb=short 2>&1 | tail -20; fi'"
          }
        ]
      }
    ]
  }
}
